#!/usr/bin/env python3
from pathlib import Path
from collections import OrderedDict
ROOT = Path(__file__).resolve().parents[1]
LANGS = ['en','it','fr','de','no','cs']

def read_ini(path):
    data=OrderedDict()
    for raw in path.read_text(encoding='utf-8', errors='replace').splitlines():
        line=raw.strip()
        if not line or line.startswith('#') or '=' not in line: continue
        k,v=line.split('=',1); data[k]=v.replace('\\n','\n')
    return data

def write_ini(path, lang, data):
    with path.open('w',encoding='utf-8',newline='\n') as f:
        f.write(f'# MadModem UI dictionary {lang}\n')
        f.write('# Generated by tools/update_ui_translations.py plus v3.11 localization sweep.\n')
        for k,v in data.items():
            f.write(f'{k}={v.replace(chr(10), "\\\\n")}\n')

