# English fix for keys that previously held marker text.
EN_KEY = {}
# Apply.
trans_dir = ROOT/'translations'
all_en = read_ini(trans_dir/'ui_en.ini')
for lang in LANGS:
    data = read_ini(trans_dir/f'ui_{lang}.ini')
    for k,en_val in all_en.items():
        if lang=='en':
            continue
        if en_val in SRC.get(lang,{}):
            data[k]=SRC[lang][en_val]
    # preserve technical values that are intentionally same; no action.
    write_ini(trans_dir/f'ui_{lang}.ini', lang, data)
print('translation overrides applied')
